/**
 * ImprovementFeed — Widget showing competitive analysis results + proposed improvements
 * Used in SystemSettingsPage to surface the 24/7 improvement pipeline output
 */
import { useState, useEffect } from 'react';
import { api } from '../utils/api';
import { RAW as HEX, fonts } from '../tokens';

export default function ImprovementFeed() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api('/system/competitive-analysis')
      .then(d => { setData(d); setLoading(false); })
      .catch(() => {
        // Try static file fallback
        fetch('/state/competitive_analysis_latest.json')
          .then(r => r.ok ? r.json() : null)
          .then(d => { if (d) setData(d); setLoading(false); })
          .catch(() => setLoading(false));
      });
  }, []);

  if (loading) return (
    <div style={{ padding: 16, color: HEX.textSecondary, fontFamily: fonts.mono, fontSize: 13 }}>
      Loading improvement feed...
    </div>
  );

  if (!data) return (
    <div style={{
      background: HEX.surface, border: `1px solid ${HEX.border}`, borderRadius: 10,
      padding: 20, fontFamily: fonts.ui,
    }}>
      <div style={{ fontSize: 14, fontWeight: 700, color: HEX.textPrimary, marginBottom: 8 }}>
        Competitive Intelligence
      </div>
      <div style={{ fontSize: 13, color: HEX.textSecondary }}>
        No analysis data available. Run competitive_monitor.py to generate.
      </div>
    </div>
  );

  const lastRun = data.timestamp || data.last_run || data.date || '--';
  const tasks = data.improvement_tasks || data.tasks || data.suggestions || [];
  const topTasks = tasks.slice(0, 5);

  const priorityColor = (p) => {
    if (p === 'high') return HEX.red;
    if (p === 'medium') return HEX.amber;
    return HEX.green;
  };

  return (
    <div style={{
      background: HEX.surface, border: `1px solid ${HEX.border}`, borderRadius: 10,
      padding: 20, fontFamily: fonts.ui,
    }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
        <div style={{ fontSize: 14, fontWeight: 700, color: HEX.textPrimary }}>
          Competitive Intelligence
        </div>
        <span style={{
          fontSize: 10, fontFamily: fonts.mono, color: HEX.textSecondary,
          background: `${HEX.blue}15`, padding: '2px 8px', borderRadius: 6,
        }}>
          Last run: {typeof lastRun === 'string' ? lastRun.slice(0, 10) : lastRun}
        </span>
      </div>

      <div style={{ display: 'flex', gap: 12, marginBottom: 16 }}>
        <div style={{
          flex: 1, background: `${HEX.blue}10`, borderRadius: 10, padding: '10px 12px',
          textAlign: 'center',
        }}>
          <div style={{ fontSize: 22, fontWeight: 800, color: HEX.blue, fontFamily: fonts.mono }}>
            {tasks.length}
          </div>
          <div style={{ fontSize: 10, color: HEX.textSecondary, textTransform: 'uppercase', letterSpacing: 0.5 }}>
            Proposed Improvements
          </div>
        </div>
        <div style={{
          flex: 1, background: `${HEX.green}10`, borderRadius: 10, padding: '10px 12px',
          textAlign: 'center',
        }}>
          <div style={{ fontSize: 22, fontWeight: 800, color: HEX.green, fontFamily: fonts.mono }}>
            {tasks.filter(t => t.priority === 'high').length}
          </div>
          <div style={{ fontSize: 10, color: HEX.textSecondary, textTransform: 'uppercase', letterSpacing: 0.5 }}>
            High Priority
          </div>
        </div>
      </div>

      {topTasks.length > 0 && (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          <div style={{ fontSize: 11, color: HEX.textSecondary, textTransform: 'uppercase', letterSpacing: 0.5, marginBottom: 4 }}>
            Top Suggestions
          </div>
          {topTasks.map((task, i) => (
            <div key={i} style={{
              display: 'flex', alignItems: 'center', gap: 8,
              padding: '8px 10px', borderRadius: 6,
              background: 'rgba(255,255,255,0.02)',
              border: `1px solid ${HEX.border}`,
            }}>
              <span style={{
                fontSize: 10, fontWeight: 700, fontFamily: fonts.mono,
                padding: '2px 6px', borderRadius: 6, textTransform: 'uppercase',
                color: priorityColor(task.priority),
                background: `${priorityColor(task.priority)}15`,
                letterSpacing: 0.4, flexShrink: 0,
              }}>
                {task.priority || 'med'}
              </span>
              <span style={{ fontSize: 13, color: HEX.textPrimary, flex: 1 }}>
                {task.title || task.description || task.prompt || 'Improvement task'}
              </span>
              <span style={{ fontSize: 10, color: HEX.textSecondary, fontFamily: fonts.mono, flexShrink: 0 }}>
                {task.app || task.category || ''}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
